head.script:
//-------------------------------------------------------------------------
// PGM명 : 거래처별손익 조정금액 (co_404_01_54b)
// 작성자 : 송정희
// 최초작성일자 : 2026-11-14
//-------------------------------------------------------------------------
scwin.fromDate_YyMm = WebSquare.date.getCurrentServerDate("yyyyMM");
scwin.check_select = true;	// 년월 변경여부 false일 경우는 재조회 및 엑셀파일 재 Import하여야 함.
scwin.hid_closeYm = "";

scwin.onpageload = function() {

    var ds_transCargoClsCd_data = [
                {"transCargoClsCd":"C","transCargoClsNm":"CNTR"}
                , {"transCargoClsCd":"B","transCargoClsNm":"BULK"}
                , {"transCargoClsCd":"E","transCargoClsNm":"기타"}
    ];

    ds_transCargoClsCd.setJSON(ds_transCargoClsCd_data );

    ed_closeYm.setValue(scwin.fromDate_YyMm);
    scwin.hid_closeYm = ed_closeYm.getValue();
    // $c.gus.cfDisableObjects([btn_AddRow, btn_CancelRow, btn_AllDeleteRow, btn_Save]);	        	
};

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function () {
    if(ed_closeYm.getValue().trim().length <= 0){
        await $c.win.alert("기준년월은 필수입력항목입니다.");
        return;
    }
    // 조회조건 필수사항 체크
    if (!$c.gus.cfValidate([ed_closeYm])) {
        return;
    }

    // dma_search.set("closeYm", ed_closeYm.getValue()); 
    // dma_search.set("acctDeptCd", ed_srchAcctDeptCd.getValue());
    // dma_search.set("clntNo", ed_clntNo.getValue());

    $c.sbm.execute(sbm_master);
};

//-------------------------------------------------------------------------
// 저장시
//-------------------------------------------------------------------------
scwin.f_Save = async function () {
   if ( !scwin.check_select ) {
       await $c.win.alert("조회 조건인 기준년월이 변경되어서 저장 하실 수 없습니다. 재 조회 후 저장 하시기 바랍니다.");
       return;
   }
    // 필수입력사항 확인
    if ( !$c.gus.cfValidate([gr_master])) {
        return;
    }
    // 변경된 사항이 있는지 확인.
    if ( ds_master.getModifiedIndex().length == 0) {
        $c.win.alert("변경된 사항이 없습니다.");
        return;
    }
    if (await $c.win.confirm(MSG_CM_CRM_001) == true) {
        $c.sbm.execute(sbm_save);
    }
};

//-------------------------------------------------------------------------
// 부서코드팝업 acctDeptCd
//-------------------------------------------------------------------------
scwin.f_acctDeptCdPopUp = function(e) { 
    udc_acctDeptCd.cfCommonPopUp(scwin.udc_acctDeptCd_callBackFunc
                        , ed_srchAcctDeptCd.getValue(),ed_srchAcctDeptNm.getValue()
                        , "T"                             // 결과가 1건 일때 원도우를	AutoClose 여부(T:Close,F:Opened)
                        , null                            // 검색 결과 컬럼의 보여주는 개수 (SELECT절의 순서) MAX:10 - default (2)
                        , null                            // Title순서
                        , null                            // 보여주는 각 컬럼들의 폭
                        , null                            // 컬럼중에서 숨기는 컬럼 지정
                        , null                            // SQL절의 WHERE절에 원하는 조건을 선택함 MAX:8개까지 가능
                        , null                            // POP-UP뛰을때 원도우의 사용자 정의 폭
                        , null                            // POP-UP뛰을때 윈도우의 사용자 정의 높이
                        , null                            // 윈도우 위치 Y좌표
                        , null                            // 윈도우 위치 X좌표
                        , null                            // 중복체크여부	("F")
                        , "F"                             // 전체검색허용여부	("F")
                        , null                            // POP-UP Window Title 검색어1,2 ("Win타이틀,첫번검색Nm,두번검색Nm")
                        );                                    
};

scwin.udc_acctDeptCd_callBackFunc = function (ret) {

    if (ret[0] != "N/A" && !$c.gus.cfIsNull(ret)) {    
        ed_srchAcctDeptCd.setValue(ret[0]);
        ed_srchAcctDeptNm.setValue(ret[1]);
	} else {
        ed_srchAcctDeptCd.setValue("");
        ed_srchAcctDeptNm.setValue("");
	}         
};

//-------------------------------------------------------------------------
// 거래처코드팝업 clntNo
//-------------------------------------------------------------------------
scwin.f_clntNoPopUp = function(e) { 
    udc_clntNo.cfCommonPopUp(scwin.udc_clntNo_callBackFunc
                        , ed_clntNo.getValue(),ed_clntNm.getValue()
                        , "T"                             // 결과가 1건 일때 원도우를	AutoClose 여부(T:Close,F:Opened)
                        , null                            // 검색 결과 컬럼의 보여주는 개수 (SELECT절의 순서) MAX:10 - default (2)
                        , null                            // Title순서
                        , null                            // 보여주는 각 컬럼들의 폭
                        , null                            // 컬럼중에서 숨기는 컬럼 지정
                        , null                            // SQL절의 WHERE절에 원하는 조건을 선택함 MAX:8개까지 가능
                        , null                            // POP-UP뛰을때 원도우의 사용자 정의 폭
                        , null                            // POP-UP뛰을때 윈도우의 사용자 정의 높이
                        , null                            // 윈도우 위치 Y좌표
                        , null                            // 윈도우 위치 X좌표
                        , null                            // 중복체크여부	("F")
                        , "F"                             // 전체검색허용여부	("F")
                        , null                            // POP-UP Window Title 검색어1,2 ("Win타이틀,첫번검색Nm,두번검색Nm")
                        );                                    
};

scwin.udc_clntNo_callBackFunc = function (ret) {

    if (ret[0] != "N/A" && !$c.gus.cfIsNull(ret)) {    
        ed_clntNo.setValue(ret[0]);
        ed_clntNm.setValue(ret[1]);
	} else {
        ed_clntNo.setValue("");
        ed_clntNm.setValue("");
	}         
};

scwin.udc_clntNo_onblurCodeEvent = function (e) {
    if (ed_clntNo.getValue().trim() == "") {
        ed_clntNm.setValue("");
    }

    if (ed_clntNo.originalValue == ed_clntNo.realValue) {
        return;
    }

    if (ed_clntNo.getValue() == "") {
        ed_clntNm.setValue("");
    } else {
        ed_clntNm.setValue("");
        scwin.f_clntNoPopUp();
    }
};

scwin.udc_clntNo_onblurNameEvent = function (e) {
    if (ed_clntNm.getValue().trim() == "") {
        ed_clntNo.setValue("");
    }

    if (ed_clntNm.originalValue == ed_clntNm.realValue) {
        return;
    }

     if (ed_clntNm.getValue() == "") {
        ed_clntNo.setValue("");
    } else {
        ed_clntNo.setValue("");
        scwin.f_clntNoPopUp();
    }
};

scwin.udc_clntNo_onclickEvent = function (e) {
    scwin.f_clntNoPopUp();
};

//-------------------------------------------------------------------------
// 파일 확장자 체크
//-------------------------------------------------------------------------
scwin.f_CheckFileExt = function (ext, path){ 
    ext = ext.toUpperCase();
    path = path.toUpperCase();
    elen = ext.length;
    flen = path.length;
    return (ext == path.substring((flen-elen), flen));
};

/**
 * 엑셀 파일 업로드
 */
scwin.f_excelUpload = async function () {

    // if ( await $c.gus.cfCheckCreateFlag() == true) {
    //     await $c.win.alert($c.data.getMessage(MSG_CM_WRN_008,["자료"]));
    //     return;
    // }

    // let ret = $c.gus.cfValidate([tb_retrieve])

    // if (!ret) {
    //     return;
    // }

    if(excelUdc.getUpExt() == "1") {
        let options = {
            "fileName": "gridDataUpload.xlsx",
            "status": "C",
            "header":"1",
            "type": "1",
            "startRowIndex":0,    // 시작row
            "skipSpace":"1",       // 공백무시 여부(1이면 무시 0이면 포함)
            "hidden":"0",           // 왼쪽히든값유무(미포함)
            "fillHidden":"0"        // 오른쪽히든값유무(무시)
        };

        ds_excel.removeAll();
        await $c.data.uploadGridViewCSV(gr_excel, options);
    } else {
        let options = {
            "fileName": "gridDataUpload.xlsx",
            "status": "C",
            "type": "1",
            "headerExist":"1",
            "startRowIndex":0,  // 시작row
            "footerExist":"0"
        };
        ds_excel.removeAll();
        await $c.data.uploadGridViewExcel(gr_excel, options);
    }
};

//-------------------------------------------------------------------------
// 엑셀 Upload
//-------------------------------------------------------------------------
scwin.f_Import = async function() { 
    if (ds_excel.getRowCount() == 0) {
        $c.gus.cfProgressWinClose();
        await $c.win.alert(MSG_CM_ERR_003);
        return;
    }

    if (await scwin.f_AddRowUploaded()) {
        $c.gus.cfProgressWinClose();
        await $c.win.alert("업로드작업이 완료되었습니다.");
    }
};

// 업로드 자료 추가
scwin.f_AddRowUploaded = async function () { 

    let check = await scwin.f_CheckUploadData();
    if (check == false) return false;    

    if (ds_excel.getRowCount() > 0) {
        ds_master.removeAll();
        for (i=0; i < ds_excel.getRowCount(); i++) {

            let row = ds_master.insertRow();

            // 관리조정금액에 ',', ' ' 값이 있을경우 제거
            let tmpMgntCtrlAmt = ds_excel.getCellData(i, "mgntCtrlAmt");
            // tmpMgntCtrlAmt = tmpMgntCtrlAmt.replace(/ /gi, "");
            // tmpMgntCtrlAmt = tmpMgntCtrlAmt.replace(/,/gi, "");

            ds_master.setCellData(row, "acctDeptCd",        ds_excel.getCellData(i, "acctDeptCd").trim());
            ds_master.setCellData(row,"acctDeptNm",       ds_excel.getCellData(i, "acctDeptNm").trim());
            ds_master.setCellData(row,"clntNo",                ds_excel.getCellData(i, "clntNo").trim());
            ds_master.setCellData(row,"clntNm",                ds_excel.getCellData(i, "clntNm").trim());
            ds_master.setCellData(row,"transCargoClsCd",   ds_excel.getCellData(i, "transCargoClsCd").trim());
            ds_master.setCellData(row,"mgntAcctCd",        ds_excel.getCellData(i, "mgntAcctCd").trim());
            ds_master.setCellData(row,"mgntAcctNm",       ds_excel.getCellData(i, "mgntAcctNm").trim());
            ds_master.setCellData(row,"mgntCtrlAmt",       tmpMgntCtrlAmt);
            ds_master.setCellData(row,"rmk",                    ds_excel.getCellData(i, "rmk").trim());
            ds_master.setCellData(row,"closeYm",               ds_excel.getCellData(i, "closeYm").trim());
        }
    }
    totalRows.setValue(ds_master.getRowCount());
    return true;
};

//-------------------------------------------------------------------------
// 업로드된 데이터 체크
//-------------------------------------------------------------------------
scwin.f_CheckUploadData = async function(){
    let sMsg = "";
    let sExtNm = "";
    if( excelUdc.getUpExt() == "1" ) {  // csv  일때
        sExtNm = "CVS";
    } else {
        sExtNm = "엑셀";
    }

    var rChkData = ds_excel.getDataRow(0);
    if ( ds_excel.getTotalCol() != 10 
    || $c.gus.cfIsNull(rChkData.acctDeptCd) 
    || rChkData.acctDeptCd == "귀속부서코드" ) {
        $c.gus.cfProgressWinClose();
        sMsg = "업로드 "+sExtNm+" 파일의 형식이 잘못되었습니다."
        + "\n엑셀 업로드 기본양식은 엑셀다운로드후,"
        + "\n첫번째 타이틀 행, 두번째 공백행, 마지막 합계행을 제거하고"
        + "\n사용하시면 됩니다. 파일형식을 확인후 다시 업로드하시길 바랍니다."
        + "\n컬럼값이 상이합니다. [형식=10개] 입력한값 => "
        + ds_excel.getTotalCol();
        await $c.win.alert(sMsg);
        return false;
    }

    // console.log("===========> 합계:"+ds_excel.getCellData(ds_excel.getTotalCol(), ds_excel.getColumnID(0)));
    // if( ds_excel.getCellData(ds_excel.getTotalCol(), ds_excel.getColumnID(0)) == "합계" ) {
    //     $c.gus.cfProgressWinClose();
    //     sMsg = "업로드 "+sExtNm+" 파일의 형식이 잘못되었습니다."
    //     + "\n사용하신 "+sExtNm+"파일의 마지막 합계행을 제거하고,"
    //     + "\n다시 사용하시길 바랍니다."
    //     ;
    //     await $c.win.alert(sMsg);
    //     return false;
    // }

    for (var i=0; i < ds_excel.getTotalRow(); i++) {
        if( ds_excel.getCellData(i,"acctDeptCd") == "합계" ) {
            $c.gus.cfProgressWinClose();
            sMsg = "업로드 "+sExtNm+" 파일의 형식이 잘못되었습니다."
            + "\n사용하신 "+sExtNm+"파일의 마지막 합계행을 제거하고,"
            + "\n다시 사용하시길 바랍니다."
            ;
            await $c.win.alert(sMsg);
            return false;
        }
        if( $c.gus.cfIsNull(ds_excel.getCellData(i,"acctDeptCd")) ) {
            $c.gus.cfProgressWinClose();
            sMsg = "업로드 "+sExtNm+" 파일의 데이터가 잘못되었습니다."
            + "\n["+i+"] 번째 행의 [귀속부서코드] 값이 없습니다.\n사용하신 "+sExtNm+"파일의 데이터를 확인 후,\n다시 업로드하시길 바랍니다."
            ;
            await $c.win.alert(sMsg);
            return false;
        }
        if( $c.gus.cfIsNull(ds_excel.getCellData(i,"clntNo")) ) {
            $c.gus.cfProgressWinClose();
            sMsg = "업로드 "+sExtNm+" 파일의 데이터가 잘못되었습니다."
            + "\n["+i+"] 번째 행의 [거래처코드] 값이 없습니다.\n사용하신 "+sExtNm+"파일의 데이터를 확인 후,\n다시 업로드하시길 바랍니다."
            ;
            await $c.win.alert(sMsg);
            return false;
        }
        if( $c.gus.cfIsNull(ds_excel.getCellData(i,"transCargoClsCd")) ) {
            $c.gus.cfProgressWinClose();
            sMsg = "업로드 "+sExtNm+" 파일의 데이터가 잘못되었습니다."
            + "\n["+i+"] 번째 행의 [구분코드] 값이 없습니다.\n사용하신 "+sExtNm+"파일의 데이터를 확인 후,\n다시 업로드하시길 바랍니다."
            ;
            await $c.win.alert(sMsg);
            return false;
        }
        if( $c.gus.cfIsNull(ds_excel.getCellData(i,"mgntAcctCd")) ) {
            $c.gus.cfProgressWinClose();
            sMsg = "업로드 "+sExtNm+" 파일의 데이터가 잘못되었습니다."
            + "\n["+i+"] 번째 행의 [관리계정코드] 값이 없습니다.\n사용하신 "+sExtNm+"파일의 데이터를 확인 후,\n다시 업로드하시길 바랍니다."
            ;
            await $c.win.alert(sMsg);
            return false;
        }
        if( $c.gus.cfIsNull(ds_excel.getCellData(i,"mgntCtrlAmt")) ) {
            $c.gus.cfProgressWinClose();
            sMsg = "업로드 "+sExtNm+" 파일의 데이터가 잘못되었습니다."
            + "\n["+i+"] 번째 행의 [금액] 값이 없습니다.\n사용하신 "+sExtNm+"파일의 데이터를 확인 후,\n다시 업로드하시길 바랍니다."
            ;
            await $c.win.alert(sMsg);
            return false;
        }
    }
    return true;
}

//-------------------------------------------------------------------------
// 각 Argument에 따른 PopUp을 호출 한다.
// 1:조회->부서 , 2:조회->거래처
// 3:입력->부서 , 4:입력->거래처 , 5:입력->계정
// code변수는 각 항목별 검색요청 값이다.
//-------------------------------------------------------------------------
scwin.f_openPopUp = function (orgObjCd, orgObjNm, select_code, sFlag) {
    var rtnList = new Array();
    var sCmdName = "";
    var param ='';
    var code = "";
    var name = "";
    // POPUP 돋보기 클릭시는 모든값을 조회 할 수 있도록 한다. flag:ALL일 경우는 돋보기 클릭한것임.
    if ( sFlag != "SKIP") {
        code = orgObjCd;
        name = orgObjNm;
    } else {
        code = orgObjCd;
        name = orgObjNm;
    }
    switch (select_code) {
        case '1' :  // sCmdName = "retrieveAcctDeptCdInfo";       
            param    = ",,,";    
            udc_acctDeptCd.cfCommonPopUp(scwin.udc_acctDeptCd_callBackFunc
                                        , code, name
                                        , sFlag                           // 결과가 1건 일때 원도우를	AutoClose 여부(T:Close,F:Opened)
                                        , null                            // 검색 결과 컬럼의 보여주는 개수 (SELECT절의 순서) MAX:10 - default (2)
                                        , null                            // Title순서
                                        , null                            // 보여주는 각 컬럼들의 폭
                                        , null                            // 컬럼중에서 숨기는 컬럼 지정
                                        , param                           // SQL절의 WHERE절에 원하는 조건을 선택함 MAX:8개까지 가능
                                        , null                            // POP-UP뛰을때 원도우의 사용자 정의 폭
                                        , null                            // POP-UP뛰을때 윈도우의 사용자 정의 높이
                                        , null                            // 윈도우 위치 Y좌표
                                        , null                            // 윈도우 위치 X좌표
                                        , null                            // 중복체크여부	("F")
                                        , "F"                             // 전체검색허용여부	("F")
                                        , null                            // POP-UP Window Title 검색어1,2 ("Win타이틀,첫번검색Nm,두번검색Nm")
                                        );     
            break;

        case '2' :  // sCmdName = "retrieveClntList";        
            param    = ",,,";
            udc_clntNo.cfCommonPopUp(scwin.udc_clntNo_callBackFunc
                                        , ed_srchAcctDeptCd.getValue(), ed_srchAcctDeptNm.getValue()
                                        , sFlag                           // 결과가 1건 일때 원도우를	AutoClose 여부(T:Close,F:Opened)
                                        , null                            // 검색 결과 컬럼의 보여주는 개수 (SELECT절의 순서) MAX:10 - default (2)
                                        , null                            // Title순서
                                        , null                            // 보여주는 각 컬럼들의 폭
                                        , null                            // 컬럼중에서 숨기는 컬럼 지정
                                        , param                           // SQL절의 WHERE절에 원하는 조건을 선택함 MAX:8개까지 가능
                                        , null                            // POP-UP뛰을때 원도우의 사용자 정의 폭
                                        , null                            // POP-UP뛰을때 윈도우의 사용자 정의 높이
                                        , null                            // 윈도우 위치 Y좌표
                                        , null                            // 윈도우 위치 X좌표
                                        , null                            // 중복체크여부	("F")
                                        , "F"                             // 전체검색허용여부	("F")
                                        , null                            // POP-UP Window Title 검색어1,2 ("Win타이틀,첫번검색Nm,두번검색Nm")
                                        );   
            break;
        case '3' :  // sCmdName = "retrieveAcctDeptCdInfo";       
            param    = ",,,";
            udc_clntNo.cfCommonPopUp(scwin.udc_clntNo_callBackFunc
                                        , code, name
                                        , sFlag                            // 결과가 1건 일때 원도우를	AutoClose 여부(T:Close,F:Opened)
                                        , null                            // 검색 결과 컬럼의 보여주는 개수 (SELECT절의 순서) MAX:10 - default (2)
                                        , null                            // Title순서
