scwin.udc_acctDeptCd_callBackFunc = function (ret) {
    if (ret[0] != "N/A" && !$c.gus.cfIsNull(ret)) {    
        ed_srchAcctDeptCd.setValue(ret[0]);
        ed_srchAcctDeptNm.setValue(ret[1]);
	} else {
        ed_srchAcctDeptCd.setValue("");
        ed_srchAcctDeptNm.setValue("");
    }         
};

